from flask import Flask, request, session, g
import redis
import functools
import time

app = Flask(__name__)
app.secret_key = 'your-secret-key-here'

# Connect to Redis
redis_client = redis.StrictRedis(host='localhost', port=6379, db=0, decode_responses=True)

@app.before_request
def load_session():
    session_id = request.cookies.get('session_id')
    if session_id:
        session_data = redis_client.get(f"session:{session_id}")
        if session_data:
            session.update(eval(session_data))

@app.after_request
def save_session(response):
    if 'session_id' not in session:
        session['session_id'] = str(int(time.time() * 1000000))
    
    session_id = session['session_id']
    redis_client.setex(f"session:{session_id}", 3600, str(dict(session)))
    response.set_cookie('session_id', session_id, max_age=3600)
    
    return response

def cache_result(expiration=300):
    def decorator(func):
        @functools.wraps(func)
        def wrapper(*args, **kwargs):
            cache_key = f"cache:{func.__name__}:{hash(str(args) + str(kwargs))}"
            cached_result = redis_client.get(cache_key)
            
            if cached_result:
                return eval(cached_result)
            
            result = func(*args, **kwargs)
            redis_client.setex(cache_key, expiration, str(result))
            return result
        return wrapper
    return decorator

@app.route('/user/<int:user_id>')
@cache_result(expiration=600)
def get_user(user_id):
    # Simulate expensive database query
    time.sleep(1)
    return {'user_id': user_id, 'name': f'User {user_id}'}

